func (stage *Stage) Checkout() {
	if stage.BackRepo != nil {
		stage.BackRepo.Checkout(stage)
	}

	stage.ComputeReverseMaps()
	stage.ComputeInstancesNb()
}

// backup generates backup files in the dirPath
func (stage *Stage) Backup(dirPath string) {
	if stage.BackRepo != nil {
		stage.BackRepo.Backup(stage, dirPath)
	}
}

// Restore resets Stage & BackRepo and restores their content from the restore files in dirPath
func (stage *Stage) Restore(dirPath string) {
	if stage.BackRepo != nil {
		stage.BackRepo.Restore(stage, dirPath)
	}
}

// backup generates backup files in the dirPath
func (stage *Stage) BackupXL(dirPath string) {
	if stage.BackRepo != nil {
		stage.BackRepo.BackupXL(stage, dirPath)
	}
}

// Restore resets Stage & BackRepo and restores their content from the restore files in dirPath
func (stage *Stage) RestoreXL(dirPath string) {
	if stage.BackRepo != nil {
		stage.BackRepo.RestoreXL(stage, dirPath)
	}
}

// insertion point for cumulative sub template with model space calls
// Stage puts a_directive to the model stage
func (a_directive *A_directive) Stage(stage *Stage) *A_directive {
	if _, ok := stage.A_directives[a_directive]; !ok {
		stage.A_directives[a_directive] = struct{}{}
		stage.A_directive_stagedOrder[a_directive] = stage.A_directiveOrder
		stage.A_directive_orderStaged[stage.A_directiveOrder] = a_directive
		stage.A_directiveOrder++
	}
	stage.A_directives_mapString[a_directive.Name] = a_directive

	return a_directive
}

// StagePreserveOrder puts a_directive to the model stage, and if the astrtuct
// was not staged before:
//
// - force the order if the order is equal or greater than the stage.A_directiveOrder
// - update stage.A_directiveOrder accordingly
func (a_directive *A_directive) StagePreserveOrder(stage *Stage, order uint) {
	if _, ok := stage.A_directives[a_directive]; !ok {
		stage.A_directives[a_directive] = struct{}{}

		if order > stage.A_directiveOrder {
			stage.A_directiveOrder = order
		}
		stage.A_directive_stagedOrder[a_directive] = order
		stage.A_directive_orderStaged[order] = a_directive
		stage.A_directiveOrder++
	}
	stage.A_directives_mapString[a_directive.Name] = a_directive
}

// Unstage removes a_directive off the model stage
func (a_directive *A_directive) Unstage(stage *Stage) *A_directive {
	delete(stage.A_directives, a_directive)
	// issue1150
	// delete(stage.A_directive_stagedOrder, a_directive)
	delete(stage.A_directives_mapString, a_directive.Name)

	return a_directive
}

// UnstageVoid removes a_directive off the model stage
func (a_directive *A_directive) UnstageVoid(stage *Stage) {
	delete(stage.A_directives, a_directive)
	// issue1150
	// delete(stage.A_directive_stagedOrder, a_directive)
	delete(stage.A_directives_mapString, a_directive.Name)
}

// commit a_directive to the back repo (if it is already staged)
func (a_directive *A_directive) Commit(stage *Stage) *A_directive {
	if _, ok := stage.A_directives[a_directive]; ok {
		if stage.BackRepo != nil {
			stage.BackRepo.CommitA_directive(a_directive)
		}
	}
	return a_directive
}

func (a_directive *A_directive) CommitVoid(stage *Stage) {
	a_directive.Commit(stage)
}

func (a_directive *A_directive) StageVoid(stage *Stage) {
	a_directive.Stage(stage)
}

// Checkout a_directive to the back repo (if it is already staged)
func (a_directive *A_directive) Checkout(stage *Stage) *A_directive {
	if _, ok := stage.A_directives[a_directive]; ok {
		if stage.BackRepo != nil {
			stage.BackRepo.CheckoutA_directive(a_directive)
		}
	}
	return a_directive
}

// for satisfaction of GongStruct interface
func (a_directive *A_directive) GetName() (res string) {
	return a_directive.Name
}

// for satisfaction of GongStruct interface
func (a_directive *A_directive) SetName(name string) {
	a_directive.Name = name
}

// Stage puts a_measure to the model stage
func (a_measure *A_measure) Stage(stage *Stage) *A_measure {
	if _, ok := stage.A_measures[a_measure]; !ok {
		stage.A_measures[a_measure] = struct{}{}
		stage.A_measure_stagedOrder[a_measure] = stage.A_measureOrder
		stage.A_measure_orderStaged[stage.A_measureOrder] = a_measure
		stage.A_measureOrder++
	}
	stage.A_measures_mapString[a_measure.Name] = a_measure

	return a_measure
}

// StagePreserveOrder puts a_measure to the model stage, and if the astrtuct
// was not staged before:
//
// - force the order if the order is equal or greater than the stage.A_measureOrder
// - update stage.A_measureOrder accordingly
